-- Seed data: 20 kotowaza for MVP
INSERT INTO kotowaza (id, japanese, reading, meaning, origin, usage_example, cultural_note) VALUES
('a1b2c3d4-0001-4000-8000-000000000001', '猿も木から落ちる', 'さるもきからおちる', '得意なことでも失敗することがある', '猿は木登りの名人だが、それでも時には落ちることがあるという観察から', '彼はベテランの料理人だが、猿も木から落ちるで、今日は塩を入れすぎてしまった。', '日本では謙虚さを重んじる文化があり、どんな達人でも油断してはいけないという教訓'),
('a1b2c3d4-0002-4000-8000-000000000002', '七転び八起き', 'ななころびやおき', '何度失敗しても諦めずに立ち上がること', '七回転んでも八回起き上がるという意味から', '事業に何度も失敗したが、七転び八起きの精神で最終的に成功した。', '日本の忍耐と粘り強さを象徴することわざ'),
('a1b2c3d4-0003-4000-8000-000000000003', '石の上にも三年', 'いしのうえにもさんねん', '辛抱強く続ければ必ず成果が出る', '冷たい石の上でも三年座り続ければ温まるという意味から', '新しい仕事は最初大変だったが、石の上にも三年で今では一人前だ。', '忍耐と継続の価値を説く日本の伝統的な教え'),
('a1b2c3d4-0004-4000-8000-000000000004', '花より団子', 'はなよりだんご', '風流よりも実利を取ること', '花見で花を見るより団子を食べる方を好む人を指して', 'お土産は花より団子で、見た目より美味しいものを選んだ。', '日本人の実用主義的な一面を表す'),
('a1b2c3d4-0005-4000-8000-000000000005', '郷に入っては郷に従え', 'ごうにいってはごうにしたがえ', 'その土地の習慣に従うべき', '新しい土地に入ったら、その土地の風習に従うのが賢明という教え', '海外に住む時は、郷に入っては郷に従えで現地の文化を尊重しよう。', '異文化理解と適応の重要性を説く'),
('a1b2c3d4-0006-4000-8000-000000000006', '急がば回れ', 'いそがばまわれ', '急ぐ時こそ安全な道を選ぶべき', '琵琶湖を渡る際、船で近道するより陸路を回る方が確実という故事から', 'プロジェクトの締切が近いが、急がば回れで基礎からしっかりやろう。', '日本の慎重さと計画性を反映'),
('a1b2c3d4-0007-4000-8000-000000000007', '塵も積もれば山となる', 'ちりもつもればやまとなる', '小さなものでも積み重なれば大きなものになる', '小さな塵でも積もれば山のように大きくなるという観察から', '毎日100円ずつ貯金すれば、塵も積もれば山となるで大きな額になる。', '日本の貯蓄文化と地道な努力を重視する価値観'),
('a1b2c3d4-0008-4000-8000-000000000008', '三人寄れば文殊の知恵', 'さんにんよればもんじゅのちえ', '凡人でも三人集まれば良い知恵が出る', '文殊菩薩は知恵の仏。凡人三人でもその知恵に匹敵するという意味', '一人で悩まず相談しよう。三人寄れば文殊の知恵だ。', '集団の知恵と協調を重視する日本文化'),
('a1b2c3d4-0009-4000-8000-000000000009', '井の中の蛙大海を知らず', 'いのなかのかわずたいかいをしらず', '狭い世界しか知らない人は視野が狭い', '井戸の中の蛙は広い海の存在を知らないという比喩', '地元だけで満足せず、井の中の蛙にならないよう世界を見よう。', '視野を広げることの大切さを説く'),
('a1b2c3d4-0010-4000-8000-000000000010', '百聞は一見に如かず', 'ひゃくぶんはいっけんにしかず', '百回聞くより一度見る方がよくわかる', '漢書「趙充国伝」に由来する中国の故事成語', '説明を聞くより実際にやってみよう。百聞は一見に如かずだ。', '経験と実践を重視する東アジア共通の価値観'),
('a1b2c3d4-0011-4000-8000-000000000011', '継続は力なり', 'けいぞくはちからなり', '続けることが大きな力になる', '何事も継続することで力がつくという教え', '毎日10分の練習を続ければ、継続は力なりで上達する。', '日本の教育文化における努力と反復の重視'),
('a1b2c3d4-0012-4000-8000-000000000012', '出る杭は打たれる', 'でるくいはうたれる', '目立つ人は非難されやすい', '並んだ杭の中で飛び出たものは打たれて揃えられることから', '新しい提案をしたら反対されたが、出る杭は打たれるものだ。', '日本社会の同調圧力と調和を重視する文化を反映'),
('a1b2c3d4-0013-4000-8000-000000000013', '能ある鷹は爪を隠す', 'のうあるたかはつめをかくす', '実力のある人は自慢しない', '有能な鷹は獲物を捕るまで爪を隠しているという観察から', '彼は静かだが実は凄い実力者だ。能ある鷹は爪を隠すとはこのことだ。', '日本の謙虚さと控えめな態度を美徳とする価値観'),
('a1b2c3d4-0014-4000-8000-000000000014', '二兎を追う者は一兎をも得ず', 'にとをおうものはいっとをもえず', '二つのことを同時に追求すると両方とも失敗する', '二匹のウサギを同時に追いかけると両方逃がすという教え', '仕事と趣味を両立しようとしたが、二兎を追う者は一兎をも得ずだった。', '集中と選択の重要性を説く'),
('a1b2c3d4-0015-4000-8000-000000000015', '雨降って地固まる', 'あめふってじかたまる', 'トラブルの後かえって良い結果になる', '雨が降った後は地面が固く締まるという自然現象から', '大喧嘩の後で本音が言えるようになった。雨降って地固まるだ。', '困難を前向きに捉える日本の楽観性'),
('a1b2c3d4-0016-4000-8000-000000000016', '早起きは三文の徳', 'はやおきはさんもんのとく', '早起きすると良いことがある', '朝早く起きれば三文の得があるという教え。三文は少額を表す', '早起きは三文の徳で、朝の散歩で素敵な景色に出会えた。', '勤勉さを美徳とする日本文化'),
('a1b2c3d4-0017-4000-8000-000000000017', '笑う門には福来る', 'わらうかどにはふくきたる', 'いつも笑顔でいる家には幸福が訪れる', '笑いが絶えない家庭には自然と福が来るという教え', 'いつも明るくしていよう。笑う門には福来るだ。', '日本のポジティブ思考と家庭の和を重視する文化'),
('a1b2c3d4-0018-4000-8000-000000000018', '蛙の子は蛙', 'かえるのこはかえる', '子は親に似るもの', '蛙の子（おたまじゃくし）は結局蛙になるという観察から', '父親も数学が得意だったから、蛙の子は蛙だね。', '血統や家系を重視する日本の伝統的価値観'),
('a1b2c3d4-0019-4000-8000-000000000019', '泣きっ面に蜂', 'なきっつらにはち', '不幸の上にさらに不幸が重なること', '泣いている顔を蜂に刺されるという比喩', '財布を落とした上に雨に降られた。泣きっ面に蜂だ。', '不運の連鎖を表現する日本語の豊かさ'),
('a1b2c3d4-0020-4000-8000-000000000020', '覆水盆に返らず', 'ふくすいぼんにかえらず', '一度起きたことは元に戻せない', '覆した水は盆には戻らないという中国の故事から', '送ってしまったメールは取り消せない。覆水盆に返らずだ。', '不可逆性を認識し、慎重に行動することの重要性')
ON CONFLICT DO NOTHING;

